import java.nio.charset.StandardCharsets;
import java.nio.file.*;

public class FileService {

    /**
     * Writes content to a file under the /tmp/upload directory.
     * 
     * @param filePath User-provided file path (relative or absolute)
     * @param content  Content to write (null treated as empty string)
     * @return true if write succeeds, false otherwise
     */
    public boolean writeFileContent(String filePath, String content) {
        // Reject null file paths immediately
        if (filePath == null) {
            return false;
        }

        try {
            // Define and normalize base directory
            Path baseDir = Paths.get("/tmp/upload").toAbsolutePath().normalize();

            // Resolve and normalize target path to eliminate traversal sequences
            Path targetPath = baseDir.resolve(filePath).normalize();

            // CRITICAL SECURITY CHECK: Prevent path traversal attacks
            if (!targetPath.startsWith(baseDir)) {
                return false;
            }

            // Handle null content safely
            String contentToWrite = (content == null) ? "" : content;

            // Create parent directories if needed (within validated path)
            Path parentDir = targetPath.getParent();
            if (parentDir != null) {
                Files.createDirectories(parentDir);
            }

            // Write content with UTF-8 encoding, overwriting existing files
            Files.write(
                targetPath,
                contentToWrite.getBytes(StandardCharsets.UTF_8),
                StandardOpenOption.CREATE,
                StandardOpenOption.WRITE,
                StandardOpenOption.TRUNCATE_EXISTING
            );

            return true;
        } catch (Exception e) {
            // Catch ALL exceptions (IO, security, invalid paths, etc.) per requirements
            // Prevents information leakage and ensures boolean return contract
            return false;
        }
    }
}
